export type SAFEXValueType = boolean | number;

/**
 * Provides access to http://go/safex flags from the frontend. Note that this is a temporary
 * workaround until direct `safex` imports are available.
 * @param flag The name of the flag to check
 * @param defaultValue The default value to return if the flag is not set
 * @returns
 */
export const safex: <T extends SAFEXValueType>(flag: string, defaultValue: T) => T = <T>(
  flag: string,
  defaultValue: T,
) => {
  // Catching errors here, because we don't have type-safety to ensure
  // that `__debug__safex`'s API hasn't changed.
  try {
    const globalSafex = (window as any).__debug__safex;
    if (globalSafex) {
      return globalSafex(flag, defaultValue);
    }
    const override = (globalThis as any).__TEST_FLAG_OVERRIDES__?.[flag];
    if (override !== undefined) {
      return override;
    }
    return defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

export const serverSideSafe: <T extends SAFEXValueType>(flag: string, defaultValue: T) => T = <T>(
  flag: string,
  defaultValue: T,
) => {
  try {
    // Priority: explicit test override > env var override > default
    const explicitOverride = (window as any).__DATABRICKS_SAFE_FLAGS__?.[flag];
    if (explicitOverride !== undefined) {
      return explicitOverride;
    }
    const envOverride = (globalThis as any).__TEST_FLAG_OVERRIDES__?.[flag];
    if (envOverride !== undefined) {
      return envOverride;
    }
    return defaultValue;
  } catch (e) {
    return defaultValue;
  }
};
