import { createContext } from 'react';

import type { ContentContextType, SidebarContextType } from './types';

const ContentContextDefaults: ContentContextType = {
  openPanelId: undefined,
  closable: true,
  destroyInactivePanels: false,
  setIsClosed: () => {},
};

const SidebarContextDefaults: SidebarContextType = {
  position: 'left',
};

export const ContentContext = createContext<ContentContextType>(ContentContextDefaults);

export const SidebarContext = createContext<SidebarContextType>(SidebarContextDefaults);
