import { useState, useEffect, useRef, useCallback } from 'react';

import { measure, update, type CancellablePromise } from './fastdom';

type Task = () => void;

/**
 * Schedules fastdom tasks with automatic cleanup on unmount.
 * Propagates the first error in a batch to the nearest Error Boundary.
 */
export function useFastDom() {
  const [error, setError] = useState<unknown>(null);
  const tasks = useRef<CancellablePromise[]>([]);

  if (error) throw error;

  useEffect(() => {
    return () => {
      tasks.current.forEach((task) => task.cancel());
    };
  }, []);

  const scheduleTask = useCallback((type: 'measure' | 'update', fn: Task) => {
    const promise = (type === 'measure' ? measure : update)(fn);
    tasks.current.push(promise);

    promise
      .catch((err) => setError((prev: unknown) => prev || err))
      .finally(() => {
        tasks.current = tasks.current.filter((t) => t !== promise);
      });

    return promise;
  }, []);

  return {
    measure: useCallback((fn: Task) => scheduleTask('measure', fn), [scheduleTask]),
    mutate: useCallback((fn: Task) => scheduleTask('update', fn), [scheduleTask]),
  };
}
